import os  # Import the OS Library module so that you can query the file system

def openFile(path, username):
    '''This function will open and return the contents of path for the user with username'''
    # Open the file specified by path to read in text mode ('r') using the Python function `open()` 
    file_handle = open('{}'.format(path), 'r')
    # Retrieve the contents of that opened file as a string, strip new line character ('\n'), and remove leading/trailing whitespace.
    fileContents = ''.join(file_handle.readlines()).strip()

    return fileContents